CREATE VIEW dbo.Indice2003
AS
SELECT     TOP 100 PERCENT MOV_SOC, MOV_ANNO, MOV_DTDOC, MOV_NDOC, MOV_DTREG, MOV_NREGIS, MOV_CONTO, MOV_TOP, MOV_TMOV
FROM         dbo.INDICE
WHERE     (MOV_SOC = '01') AND (MOV_ANNO = '2003')
ORDER BY MOV_DTREG

GO
SET QUOTED_IDENTIFIER OFF 
GO
SET ANSI_NULLS ON 
GO

